// Generates a valid 0.1-second 8 kHz mono PCM WAV (silence) at module load
// and exposes it as a real `File`. Tests use this for any code path that needs
// a playable audio source (audio engine, drop zone, etc.).

const SAMPLE_RATE = 8000;
const DURATION_SECONDS = 0.1;
const SAMPLE_COUNT = Math.round(SAMPLE_RATE * DURATION_SECONDS);

function buildSilentWav(): Uint8Array {
  const dataLength = SAMPLE_COUNT * 2;
  const buffer = new ArrayBuffer(44 + dataLength);
  const view = new DataView(buffer);

  const writeString = (offset: number, text: string) => {
    for (let i = 0; i < text.length; i++) view.setUint8(offset + i, text.charCodeAt(i));
  };

  writeString(0, "RIFF");
  view.setUint32(4, 36 + dataLength, true);
  writeString(8, "WAVE");
  writeString(12, "fmt ");
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, SAMPLE_RATE, true);
  view.setUint32(28, SAMPLE_RATE * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  writeString(36, "data");
  view.setUint32(40, dataLength, true);

  return new Uint8Array(buffer);
}

const SILENT_WAV_BYTES = buildSilentWav();

function createAudioFile(name = "silence.wav"): File {
  return new File([SILENT_WAV_BYTES], name, { type: "audio/wav" });
}

// A ~0.3-second stereo 44.1 kHz silent mp3, used by tests that need a real
// decodable mp3 source (the audio engine's decode-to-wav path).
const SILENT_MP3_BASE64 =
  "";

function base64ToBytes(base64: string): Uint8Array {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

const SILENT_MP3_BYTES = base64ToBytes(SILENT_MP3_BASE64);

function createMp3File(name = "silence.mp3"): File {
  return new File([SILENT_MP3_BYTES], name, { type: "audio/mpeg" });
}

function makeSineBuffer(durationS: number, sampleRate = 44100): AudioBuffer {
  const ctx = new AudioContext();
  const length = Math.max(1, Math.round(sampleRate * durationS));
  const audioBuffer = ctx.createBuffer(1, length, sampleRate);
  const data = audioBuffer.getChannelData(0);
  for (let i = 0; i < length; i++) {
    data[i] = Math.sin((2 * Math.PI * 440 * i) / sampleRate) * 0.2;
  }
  return audioBuffer;
}

export { createAudioFile, createMp3File, makeSineBuffer };
